section.content:
// Example: Key message selection
{
  "questions": [{
    "question": "Which message framing resonates best for 'The Problem' section?",
    "header": "Key Message",
    "options": [
      {"label": "Direct Challenge", "description": "\"Most teams waste 40% of meeting time on slides\""},
      {"label": "Question Hook", "description": "\"What if your slides could build themselves?\""},
      {"label": "Story Setup", "description": "\"Last month, a SC spent 6 hours on one deck...\""},
      {"label": "Data Lead", "description": "\"73% of deals are won or lost at the presentation stage\""}
    ],
    "multiSelect": false
  }]
}

The tool accepts this structure:
{
  "questions": [{
    "question": "string (the question to ask)",
    "header": "string (short label, max 12 chars)",
    "options": [
      {"label": "string", "description": "string"}
    ],
    "multiSelect": boolean
  }]
}
- Maximum 4 questions per call
- Maximum 4 options per question
- User can always select "Other" for custom input

interface.schema:
agenda_sections: [
  {
    id: "agenda-1",                    // Unique identifier
    title: "Opening Hook",             // Section name
    narrative_role: "opening",         // One of: opening | context | problem | solution | evidence | cta
    estimated_slides: 1,               // 1-3 slides per section
    description: "Grab attention...",  // 1-sentence purpose

    // NEW: Added by Story 13.2
    discovery: {
      key_message: "Most teams waste 40% of meeting time on slides"  // Selected framing text
    }
  }
]

interface.contract:
{
  "questions": [{
    "question": "Which message framing resonates best for '{{section.title}}'?",
    "header": "Message",           // Max 12 chars
    "options": [
      {"label": "Direct Challenge", "description": "{{direct_framing_text}}"},
      {"label": "Question Hook", "description": "{{question_framing_text}}"},
      {"label": "Story Setup", "description": "{{story_framing_text}}"},
      {"label": "Data Lead", "description": "{{data_framing_text}}"}
    ],
    "multiSelect": false           // CRITICAL: Single-select for message framings
  }]
}

Constraints:
- Max 4 questions per call
- Max 4 options per question
- "Other" option automatically available for custom input
- Returns selected option label or custom text
